#![allow(unused)]

use bytes::Bytes;
use message::message::from_bytes;
use message::utils::UTFString;
use serde::Deserialize;

#[derive(Debug, Deserialize)]
struct P {
    max_id: u32,
    mid_id: u32,
    min_id: u32,
    rank: Vec<R>,
}

#[derive(Debug, Deserialize)]
struct R {
    uid: i32,
    _a: u32,
    rank: i32,
    _b: u32,
    time: i32,
    score: i32,
    nick: UTFString,
}

fn main() {
    let h = "";
    let vec = hex::decode(h).unwrap();
    let mut bytes = Bytes::from_owner(vec);
    let p: P = from_bytes(&mut bytes).unwrap();
    println!("{:?}", p);
}
